import{_ as t,o as a,c as o,a2 as r}from"./chunks/framework.ufzXw1qY.js";const p=JSON.parse('{"title":"API Overview","description":"Technical architecture of the OpenSIN-AI API ecosystem.","frontmatter":{"title":"API Overview","description":"Technical architecture of the OpenSIN-AI API ecosystem."},"headers":[],"relativePath":"api/overview.md","filePath":"api/overview.md"}'),i={name:"api/overview.md"};function n(s,e,l,c,d,h){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="api-overview" tabindex="-1">API Overview <a class="header-anchor" href="#api-overview" aria-label="Permalink to &quot;API Overview&quot;">​</a></h1><p>The OpenSIN-AI ecosystem exposes two primary API layers: the <strong>Local SDK Layer</strong> for internal agent logic and the <strong>Remote A2A Layer</strong> for cross-agent communication via the Neural-Bus.</p><h2 id="core-protocols" tabindex="-1">Core Protocols <a class="header-anchor" href="#core-protocols" aria-label="Permalink to &quot;Core Protocols&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Protocol</th><th>Purpose</th><th>Implementation</th></tr></thead><tbody><tr><td><strong>MCP</strong></td><td>Local tool discovery and execution</td><td><a href="https://modelcontextprotocol.io" target="_blank" rel="noreferrer">Model Context Protocol</a></td></tr><tr><td><strong>A2A</strong></td><td>Decentralized agent-to-agent communication</td><td>JSON-RPC 2.0 over HTTPS/NATS</td></tr><tr><td><strong>Neural-Bus</strong></td><td>Real-time event mesh and state sync</td><td>NATS JetStream</td></tr></tbody></table><h2 id="api-surfaces" tabindex="-1">API Surfaces <a class="header-anchor" href="#api-surfaces" aria-label="Permalink to &quot;API Surfaces&quot;">​</a></h2><h3 id="_1-agent-identity-api" tabindex="-1">1. Agent Identity API <a class="header-anchor" href="#_1-agent-identity-api" aria-label="Permalink to &quot;1. Agent Identity API&quot;">​</a></h3><p>Used for discovery and capability advertising. Every agent must expose a <code>.well-known/agent-card.json</code>.</p><ul><li><strong>Primary Entry:</strong> <code>GET /.well-known/agent-card.json</code></li><li><strong>Purpose:</strong> Public contract metadata (skills, tools, auth schemes).</li></ul><h3 id="_2-a2a-communication-api" tabindex="-1">2. A2A Communication API <a class="header-anchor" href="#_2-a2a-communication-api" aria-label="Permalink to &quot;2. A2A Communication API&quot;">​</a></h3><p>The primary interface for agents to exchange tasks and observations.</p><ul><li><strong>Standard:</strong> JSON-RPC 2.0</li><li><strong>Base Route:</strong> <code>/a2a/v1</code></li><li><strong>Key Methods:</strong> <code>tools/call</code>, <code>agent/spawn</code>, <code>observation/push</code></li></ul><h3 id="_3-team-orchestration-api" tabindex="-1">3. Team Orchestration API <a class="header-anchor" href="#_3-team-orchestration-api" aria-label="Permalink to &quot;3. Team Orchestration API&quot;">​</a></h3><p>Managed by <code>Team-SIN-*</code> agents to coordinate multi-agent workflows.</p><ul><li><strong>Purpose:</strong> Parallel task distribution and result aggregation.</li><li><strong>Backbone:</strong> SIN-Hermes Router.</li></ul><h2 id="authentication" tabindex="-1">Authentication <a class="header-anchor" href="#authentication" aria-label="Permalink to &quot;Authentication&quot;">​</a></h2><p>OpenSIN uses a tiered authentication model managed by the <a href="/guide/passwordmanager.html">Passwordmanager</a>:</p><ol><li><strong>Bearer Token (JWT):</strong> Standard for public A2A endpoints.</li><li><strong>Mutual TLS (mTLS):</strong> Required for Neural-Bus core infrastructure.</li><li><strong>Skill-Based Scopes:</strong> Granular permissions per tool execution.</li></ol><h2 id="rate-limiting-safety" tabindex="-1">Rate Limiting &amp; Safety <a class="header-anchor" href="#rate-limiting-safety" aria-label="Permalink to &quot;Rate Limiting &amp; Safety&quot;">​</a></h2><p>All API calls are subject to the <strong>Permission Manager</strong> gate. Destructive actions or high-cost model calls are paused for human approval unless pre-authorized.</p><hr><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/api/a2a.html">A2A Protocol Specification</a></li><li><a href="/api/agent.html">Agent Identity API</a></li><li><a href="/architecture/global-brain-neural-bus.html">Neural-Bus Overview</a></li></ul>',22)])])}const m=t(i,[["render",n]]);export{p as __pageData,m as default};
